// ── Apply filter to RecommendationInput ──────────────────────
function applyFilterToInput(input: RecommendationInput, filter: AppliedFilter): RecommendationInput {
  let updated = { ...input }
  updated = applySingleFilter(updated, filter)

  // Apply side filters if present (from multi-param extraction)
  const sideFilters = (filter as unknown as Record<string, unknown>)._sideFilters as AppliedFilter[] | undefined
  if (sideFilters && Array.isArray(sideFilters)) {
    for (const sf of sideFilters) {
      updated = applySingleFilter(updated, sf)
    }
  }

  return updated
}

function applySingleFilter(input: RecommendationInput, filter: AppliedFilter): RecommendationInput {
  const updated = { ...input }

  // "상관없음" / skip → 해당 필드 클리어
  if (filter.op === "skip" || filter.rawValue === "skip") {
    switch (filter.field) {
      case "diameterMm":
      case "diameterRefine":
        updated.diameterMm = undefined
        break
      case "fluteCount":
        updated.flutePreference = undefined
        break
      case "coating":
        updated.coatingPreference = undefined
        break
      case "cuttingType":
        updated.operationType = undefined
        break
      case "material":
        updated.material = undefined
        break
      case "toolSubtype":
        updated.toolSubtype = undefined
        break
    }
    return updated
  }

  // ── IMPORTANT: narrowing filters (fluteCount, coating, toolSubtype, seriesName, cuttingType)
  // are applied IN-MEMORY by runHybridRetrieval, NOT here.
  // Only diameter and material affect DB query input, because they are base conditions.
  // Setting narrowing fields on input causes DB to re-query with different results
  // than what the question engine counted from the current pool.
  switch (filter.field) {
    case "diameterMm":
    case "diameterRefine":
      updated.diameterMm = typeof filter.rawValue === "number" ? filter.rawValue : parseFloat(String(filter.rawValue))
      break
    case "material":
      updated.material = String(filter.rawValue)
      break
    // fluteCount, coating, toolSubtype, seriesName, cuttingType
    // → handled by in-memory filters in runHybridRetrieval, NOT on input
  }
  return updated
}

// ── Build Stage History from Filters (bootstrap when no history exists) ──
function buildStageHistoryFromFilters(
  filters: AppliedFilter[],
  currentInput: RecommendationInput,
  currentCandidateCount: number
): NarrowingStage[] {
  // Build initial stage
  const stages: NarrowingStage[] = [{
    stepIndex: -1,
    stageName: "initial_search",
    filterApplied: null,
    candidateCount: currentCandidateCount,
    resolvedInputSnapshot: { ...currentInput },
    filtersSnapshot: [],
  }]

  // Build a stage for each applied filter
  let accumulatedFilters: AppliedFilter[] = []
  for (const f of filters) {
    accumulatedFilters = [...accumulatedFilters, f]
    stages.push({
      stepIndex: f.appliedAt,
      stageName: `${f.field}_${f.value}`,
      filterApplied: f,
      candidateCount: currentCandidateCount, // approximate — we don't have historical counts here
      resolvedInputSnapshot: { ...currentInput },
      filtersSnapshot: [...accumulatedFilters],
    })
  }

  return stages
}

// ── Debug: Log Narrowing State ──────────────────────────────
function logNarrowingState(
  phase: string,
  state: ExplorationSessionState,
  currentField: string | null
): void {
  console.log(`[narrowing:${phase}] ───────────────────────────`)
  console.log(`[narrowing:${phase}] Session: ${state.sessionId}`)
  console.log(`[narrowing:${phase}] Candidates: ${state.candidateCount}`)
  console.log(`[narrowing:${phase}] Status: ${state.resolutionStatus}`)
  console.log(`[narrowing:${phase}] Turn: ${state.turnCount}`)
  console.log(`[narrowing:${phase}] Filters: ${state.appliedFilters.map(f => `${f.field}=${f.value}`).join(", ") || "(none)"}`)
  console.log(`[narrowing:${phase}] Stages: ${state.stageHistory?.map(s => s.stageName).join(" → ") || "(none)"}`)
  if (currentField) {
    console.log(`[narrowing:${phase}] Next question field: ${currentField}`)
  }
  console.log(`[narrowing:${phase}] ───────────────────────────`)
}

// ── Map CandidateSnapshot to displayedProducts format for LLM prompts ──
function snapshotToDisplayed(snapshot: CandidateSnapshot[]): DisplayedProduct[] {
  return snapshot.slice(0, 10).map(c => ({
    rank: c.rank,
    code: c.displayCode,
    brand: c.brand,
    series: c.seriesName,
    diameter: c.diameterMm,
    flute: c.fluteCount,
    coating: c.coating,
    materialTags: c.materialTags,
    score: c.score,
    matchStatus: c.matchStatus,
  }))
}

// ── Build Candidate Snapshot (lightweight for UI) ────────────
function buildCandidateSnapshot(
  candidates: ScoredProduct[],
  evidenceMap: Map<string, EvidenceSummary>
): CandidateSnapshot[] {
  return candidates.map((c, i) => {
    const ev = evidenceMap.get(c.product.normalizedCode)
    return {
      rank: i + 1,
      productCode: c.product.normalizedCode,
      displayCode: c.product.displayCode,
      displayLabel: buildProductLabel(c.product),
      brand: c.product.brand ?? null,
      seriesName: c.product.seriesName,
      seriesIconUrl: c.product.seriesIconUrl ?? null,
      diameterMm: c.product.diameterMm,
      fluteCount: c.product.fluteCount,
      coating: c.product.coating,
      materialTags: c.product.materialTags,
      score: c.score,
      scoreBreakdown: c.scoreBreakdown,
      matchStatus: c.matchStatus,
      stockStatus: c.stockStatus,
      totalStock: c.totalStock,
      hasEvidence: !!ev && ev.chunks.length > 0,
      bestCondition: ev?.bestCondition ?? null,
    }
  })
}

// ════════════════════════════════════════════════════════════════
// SIMPLE CHAT HANDLER (legacy)
// ════════════════════════════════════════════════════════════════

async function handleSimpleChat(messages: ChatMessage[], mode: string): Promise<Response> {
  if (!messages.length) {
    return NextResponse.json({ error: "messages required" }, { status: 400 })
  }

  const latestUserMsg = [...messages].reverse().find(m => m.role === "user")?.text ?? ""
  const baseInput = normalizeInput(latestUserMsg)
  const provider = getProvider()

  // Quick check if enough info
  const hasEnough = !!(baseInput.diameterMm || (baseInput.material && baseInput.operationType))

  if (hasEnough) {
    const result = await runHybridRetrieval(baseInput, [], 5)
    const { primary, alternatives, status } = classifyHybridResults(result)
    const warnings = primary ? buildWarnings(primary, baseInput) : []
    const rationale = primary ? buildRationale(primary, baseInput) : []

    const deterministicSummary = buildDeterministicSummary({
      status, query: baseInput, primaryProduct: primary, alternatives,
      warnings, rationale, sourceSummary: [], deterministicSummary: "",
      llmSummary: null, totalCandidatesConsidered: result.totalConsidered,
    })

    const recommendation: RecommendationResult = {
      status, query: baseInput, primaryProduct: primary, alternatives,
      warnings, rationale, sourceSummary: primary ? buildSourceSummary(primary) : [],
      deterministicSummary, llmSummary: null,
      totalCandidatesConsidered: result.totalConsidered,
    }

    // Inject brand if missing
    let quickText = deterministicSummary
    if (primary && primary.product.brand) {
      const brandName = primary.product.brand
      const hasBrand = quickText.includes(brandName) || /브랜드명/.test(quickText)
      if (!hasBrand) {
        quickText = `**브랜드명:** ${brandName} | **제품코드:** ${primary.product.displayCode}\n\n${quickText}`
      }
    }

    return NextResponse.json({
      text: quickText,
      purpose: "recommendation",
      chips: getFollowUpChips(recommendation),
      isComplete: true,
      recommendation,
      sessionState: null,
      evidenceSummaries: null,
      candidateSnapshot: null,
    })
  }

  // Not enough info — ask question
  return NextResponse.json({
    text: getNextQuestion(baseInput),
    purpose: "question",
    chips: getDefaultChips(baseInput),
    isComplete: false,
    recommendation: null,
    sessionState: null,
    evidenceSummaries: null,
    candidateSnapshot: null,
  })
}

